const scheduler = () => {
  const queue = [];
  let running = false;
  const run = async () => {
    if (running) return;
    running = true;
    while (queue.length) {
      const task = queue.shift();
      await task();
    }
    running = false;
  };
  return (task) => { queue.push(task); run(); };
};
const schedule = scheduler();
schedule(async () => { console.log('A'); });
schedule(async () => { console.log('B'); });
schedule(async () => { console.log('C'); });
